-- <% MACRO\HEADER %>
CREATE PROCEDURE [dbo].[PS_CB_Diversity_Score]
/*******************************************************************
* PURPOSE:  Calculates diversity score
* NOTES: 
* DATE CREATED: 2/8/2010 scaffo
* MODIFIED 
* DATE		AUTHOR		DESCRIPTION
*-------------------------------------------------------------------
*05/18/2012	SC	#3200 Changed field_name to varchar(100)
*08/13/2012	SC	Removed equities
*03/06/2013	SC	#3683 Added @include_regions
*03/12/2014	SC	#4512 Added @asset_count
*03/17/2015	SC	#7126 Added additional summary data
*02/11/2016	SC	#14773 Added error details results
*10/02/2016	SC	#26073 Codes/fields to varchar(100)
*12/11/2018	SC	#54727 Added @rating_agency
*07/22/2020	SC	#76666 PS_Issue redesign
*08/11/2020	KK	#143873 Added KBRA
*09/16/2025	NA	Added use_display_name for PS_CT_Details_Display
*******************************************************************/
(
	@psv_id int,
	@dcb_id int,
	@run_mode lookup_code,	
		/*	SAVE - run and save results, do not display
			DISP - display calculation details, do not save
			FULL - run, save, and display results
		*/
	@recordset_code varchar(50) = 'ALL', --ALL, DETAILS, VARIABLES, SUMMARY, ERROR_INFO--
	@result_variable varchar(100),
	@result_variable2 varchar(100) = NULL,	--the number of assets used--
	@rating_agency dbo.lookup_code = 'MR',
	@principal_balance_method lookup_code,
	@currency_option lookup_code,
		/* 
			To aggregate, amounts must be in the same currency. So Either 
			   a)only look up issues with a specified currency or 
			   b)convert to a single currency
			'DEAL' - convert all balances to one functional currency
			'USD' - restrict issue or account to a single currency 
		*/
	@include_unfunded_commitment tinyint, 
		/* include unfunded commitment
			0 - no
			1 - yes 
		*/
	@include_regions tinyint,
		/* include unfunded commitment
			0 - no
			1 - yes 
		*/
	@aggregate_attributable_amount lookup_code = 'AA', 
		/*  
			value to use aggregate attributable amount		
			'AA' - use where available
			'IC' - use issuer country only
		*/
	@layout_code varchar(100) = NULL,
	@applicability_expression varchar(max) = NULL,
	@rounding_method lookup_code = 'NO',
	@rounding_precision smallint = NULL,	
	@user_id [user_id] = NULL,
	@operation_confirmed tinyint = 1,
	@silent_mode tinyint = 1,
	@use_display_name bit = 1			
	
)
AS
BEGIN

	SET NOCOUNT ON;
	BEGIN TRY;

		DECLARE
			@proc_name sysname,
			@tran_count int,
			@save_tran bit = 0,
			@message_code varchar(50),
			@operation_details varchar(1000),
			@operation_primary_key varchar(1000),
			@pk_id int;

		SELECT 
			@proc_name = object_name(@@procid),
			@tran_count = @@trancount,
			@pk_id = @psv_id,
			@operation_primary_key = 'psv_id;' + CAST(@psv_id AS varchar);
			
		
		IF @@NESTLEVEL = 1
		OR OBJECT_ID('tempdb..#cdosys_stack') IS NULL
		BEGIN
			DROP TABLE IF EXISTS #cdosys_stack;
			CREATE TABLE #cdosys_Stack(proc_id INT, nest_level INT, stack_type VARCHAR(25), preserve TINYINT DEFAULT(0), stack_message NVARCHAR(4000));
		END;

		 IF ISNULL(dbo.ConfigValue('PS_GEN_TRAN', NULL),0) = 1 
		AND dbo.cdosys_ContextInfo_True('NOTRAN') = 0
		BEGIN
			IF @@trancount = 0
				BEGIN TRAN @proc_name;
			ELSE
			BEGIN
				SAVE TRAN @proc_name;
				SET @save_tran = 1;
			END
		END



		--Start--
		EXEC dbo.cdosys_Start_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,			
			@starting_tran_count = @tran_count,
			@pk_id = @pk_id, 
			@row_version = NULL, 
			@operation_confirmed = @operation_confirmed;
			

		DECLARE
			@ps_id int,
			@ts_id int,
			@entity_id int,
			@aggr_level lookup_code,
			@obligor_count int,
			@issue_count int,
			@average_obligor_balance money,
			@numerator float, 
			@industry_diversity_score float,
			@industry_diversity_score_char varchar(25),
			@source_expression varchar (max),
			@parameter_variable varchar(max),
			@fields varchar(max),
			@join_mode varchar(50),
			@region_details varchar(255),
			@extra_fields varchar(255),
			@asset_count int;

		CREATE TABLE #item_calculations 
		(
			ps_issue_id bigint NOT NULL,
			ps_item_id bigint NULL,
			current_par_amount money NULL,
			current_par_amount_deal_currency money NULL,
			balance money NULL,
			balance_currency varchar(4) NULL,
			country_code varchar(3) NULL,
			obligor_country_code varchar(3) NULL,
			country_name varchar(255) NULL,
			obligor_country_name varchar(255) NULL,
			item_pik_factor float,
			cap_int_amount money			
		);
		
		CREATE TABLE #obligor_summary 
		( 
			industry varchar(100),
			obligor_id int,
			obligor_name varchar(100),
			em_region_code varchar(25),
			balance money,
			average_balance money,
			equivalent_unit_score decimal(10,5)
		);

		CREATE TABLE #industry_summary 
		(
			industry varchar(100),
			em_region_code varchar(25),
			aggr_industry_EUS decimal(10,5),
			industry_diversity_score decimal(5,4)
		);
		
		CREATE TABLE #error_info (ps_issue_id bigint NOT NULL, obligor_id int, industry_name varchar(100), facility_id bigint, error_details varchar(8000) NULL);
					
		SELECT @ps_id = ps_id, @ts_id = ts_id FROM dbo.PS_Version WHERE psv_id = @psv_id;
		SELECT @entity_id = dbo.PS_EntityId(@ps_id);

		EXEC dbo.EXP_Expression_Expand @source_expression = @applicability_expression, @include_aggr_level = 1, @user_id = @user_id, @aggr_level = @aggr_level OUTPUT;
		SET @aggr_level = ISNULL(@aggr_level, 'ISSU');  --if we have a lot level filter, use lot level--

		IF @rating_agency NOT IN ('DBRS', 'KBRA', 'FR', 'MR', 'SPR')
			SET @rating_agency = 'MR';

		--Load #item_calculations with item level balances--
		EXEC dbo.PS_CB_Balance_Load
			@psv_id = @psv_id,
			@issue_category = 'A',
			@principal_balance_method = @principal_balance_method,
			@currency_option = @currency_option,
			@include_unfunded_commitment = @include_unfunded_commitment,
			@aggr_level = @aggr_level,
			@aggregate_attributable_amount = @aggregate_attributable_amount,
			@applicability_expression = @applicability_expression,
			@user_id = @user_id,
			@operation_confirmed = @operation_confirmed,
			@silent_mode = @silent_mode;

		--Remove Equities--
		DELETE ic FROM #item_calculations ic INNER JOIN dbo.PS_Issue psi ON ic.ps_issue_id = psi.ps_issue_id AND psi.issue_type = 'E';
	
			
		--Calculate summary per obligor industry--
		IF @include_regions = 0
		BEGIN
			INSERT INTO #obligor_summary (industry, obligor_id, obligor_name, balance)
				SELECT 	
					CASE @rating_agency
						WHEN 'DBRS' THEN dbrs_obligor_industry
						WHEN 'KBRA' THEN kbra_obligor_industry
						WHEN 'FR' THEN fitch_obligor_industry
						WHEN 'MR' THEN moody_obligor_industry
						WHEN 'SPR' THEN sp_obligor_industry
						ELSE moody_obligor_industry
					END,
					obligor_id, 
					obligor_name, 
					SUM(balance)
				FROM
					#item_calculations ic
					INNER JOIN dbo.PS_issue psi ON ic.ps_issue_id = psi.ps_issue_id
				GROUP BY 
					CASE @rating_agency
						WHEN 'DBRS' THEN dbrs_obligor_industry
						WHEN 'KBRA' THEN kbra_obligor_industry
						WHEN 'FR' THEN fitch_obligor_industry
						WHEN 'MR' THEN moody_obligor_industry
						WHEN 'SPR' THEN sp_obligor_industry
						ELSE moody_obligor_industry
					END,
					obligor_id, 
					obligor_name;
		END
		ELSE --Calculate summary per obligor industry and region--
		BEGIN
			INSERT INTO #obligor_summary (industry, obligor_id, obligor_name, em_region_code, balance)
				SELECT 	
					CASE @rating_agency
						WHEN 'DBRS' THEN dbrs_obligor_industry
						WHEN 'KBRA' THEN kbra_obligor_industry
						WHEN 'FR' THEN fitch_obligor_industry
						WHEN 'MR' THEN moody_obligor_industry
						WHEN 'SPR' THEN sp_obligor_industry
						ELSE moody_obligor_industry
					END,
					obligor_id, 
					obligor_name,
					CASE WHEN di.industry_id IS NULL THEN ISNULL(
						CASE @rating_agency
							WHEN 'DBRS' THEN dbrs_em_region_code
							WHEN 'KBRA' THEN kbra_em_region_code
							WHEN 'FR' THEN fitch_em_region_code
							WHEN 'MR' THEN moody_em_region_code
							WHEN 'SPR' THEN sp_em_region_code
							ELSE moody_em_region_code
						END, 'ALL')					
					 ELSE 'ALL' END,
					SUM(balance)
				FROM
					#item_calculations ic
					INNER JOIN dbo.PS_issue psi ON ic.ps_issue_id = psi.ps_issue_id
					LEFT OUTER JOIN dbo.Deal_industry di
						 ON di.entity_id = @entity_id
						AND di.rating_agency = @rating_agency
						AND di.exclude_region = 1
						AND di.industry_number = psi.mr_obligor_industry_number
						
				GROUP BY 
					CASE @rating_agency
						WHEN 'DBRS' THEN dbrs_obligor_industry
						WHEN 'KBRA' THEN kbra_obligor_industry
						WHEN 'FR' THEN fitch_obligor_industry
						WHEN 'MR' THEN moody_obligor_industry
						WHEN 'SPR' THEN sp_obligor_industry
						ELSE moody_obligor_industry
					END,
					obligor_id, 
					obligor_name,
					CASE WHEN di.industry_id IS NULL THEN ISNULL(
						CASE @rating_agency
							WHEN 'DBRS' THEN dbrs_em_region_code
							WHEN 'KBRA' THEN kbra_em_region_code
							WHEN 'FR' THEN fitch_em_region_code
							WHEN 'MR' THEN moody_em_region_code
							WHEN 'SPR' THEN sp_em_region_code
							ELSE moody_em_region_code
						END, 'ALL')					
					 ELSE 'ALL' END;
		END		

		--numerator--
		SELECT @numerator = ISNULL(SUM(balance), 0), @issue_count = COUNT(*) FROM #item_calculations;
		SELECT @obligor_count = COUNT(*) FROM #obligor_summary;		
		IF @obligor_count = 0
			SELECT @message_code = 'SUMMARYOBLIG_MISSING';
		ELSE		
			SELECT @average_obligor_balance = @numerator / @obligor_count;


		--Calculate equivalent unit score per obligor (issuer)-- 
		UPDATE 	
			#obligor_summary
		SET
			average_balance = @average_obligor_balance,
			equivalent_unit_score = 
				CASE 
					WHEN CONVERT(float, balance) / @average_obligor_balance > 1 THEN 1 
					ELSE CONVERT(float, balance) / @average_obligor_balance 
				END;

			
		--Calculate aggregate unit score on industry level--
		IF @include_regions = 0
		BEGIN
			INSERT INTO #industry_summary (industry, aggr_industry_EUS, industry_diversity_score)
				SELECT 	
					industry, 
					SUM(equivalent_unit_score), 
					NULL
				FROM
					#obligor_summary
				GROUP BY 
					industry;
		END
		ELSE
		BEGIN
			INSERT INTO #industry_summary (industry, em_region_code, aggr_industry_EUS, industry_diversity_score)
				SELECT 	
					industry,
					em_region_code,
					SUM(equivalent_unit_score), 
					NULL
				FROM
					#obligor_summary
				GROUP BY 
					industry,
					em_region_code;
		END

		--Calculate diversity score for each industry in the table--
		UPDATE #industry_summary
		SET 	
			industry_diversity_score =  ROUND(
			CASE 	
				WHEN aggr_industry_EUS <= 1 THEN ROUND(aggr_industry_EUS,1)  
				WHEN aggr_industry_EUS > 1  AND aggr_industry_EUS <= 3 THEN ROUND(aggr_industry_EUS - 1, 1)/2 + 1  
				WHEN aggr_industry_EUS > 3  AND aggr_industry_EUS <= 6 THEN ROUND(aggr_industry_EUS - 3, 1)/3 + 2  
				WHEN aggr_industry_EUS > 6  AND aggr_industry_EUS <= 10 THEN ROUND(aggr_industry_EUS - 6,1)/4 + 3  
				WHEN aggr_industry_EUS > 10 AND aggr_industry_EUS <= 20 THEN ROUND(aggr_industry_EUS - 10, 1)/10 + 4
				ELSE 5
			END, 4);
							

		SET @industry_diversity_score = CONVERT(float, (SELECT SUM(industry_diversity_score) FROM #industry_summary));
		SET @industry_diversity_score_char = dbo.PC_Round_Char(@industry_diversity_score, @rounding_method, @rounding_precision);

		--find missing info/data issues so we can display it to user--
		IF @include_regions = 0
			INSERT INTO #error_info (ps_issue_id, obligor_id,  industry_name, facility_id, error_details)
				SELECT DISTINCT
					psi.ps_issue_id,
					psi.obligor_id,
					CASE @rating_agency
						WHEN 'DBRS' THEN psi.dbrs_obligor_industry
						WHEN 'KBRA' THEN psi.kbra_obligor_industry
						WHEN 'FR' THEN  psi.fitch_obligor_industry
						WHEN 'MR' THEN  psi.moody_obligor_industry
						WHEN 'SPR' THEN  psi.sp_obligor_industry
						ELSE  psi.moody_obligor_industry
					END,
					psi.facility_id,
					'Obligor Multiple Industries'
				FROM
					#item_calculations tp 
					INNER JOIN dbo.PS_issue psi ON tp.ps_issue_id = psi.ps_issue_id
					INNER JOIN dbo.PS_issue psi2 
							ON psi.obligor_id = psi2.obligor_id
							AND
							ISNULL(CASE @rating_agency
								WHEN 'DBRS' THEN psi.dbrs_obligor_industry
								WHEN 'KBRA' THEN psi.kbra_obligor_industry
								WHEN 'FR' THEN  psi.fitch_obligor_industry
								WHEN 'MR' THEN  psi.moody_obligor_industry
								WHEN 'SPR' THEN  psi.sp_obligor_industry
								ELSE  psi.moody_obligor_industry
							END, 'XX')
							<>
							ISNULL(CASE @rating_agency
								WHEN 'DBRS' THEN psi2.dbrs_obligor_industry
								WHEN 'KBRA' THEN psi2.kbra_obligor_industry
								WHEN 'FR' THEN  psi2.fitch_obligor_industry
								WHEN 'MR' THEN  psi2.moody_obligor_industry
								WHEN 'SPR' THEN  psi2.sp_obligor_industry
								ELSE  psi2.moody_obligor_industry
							END, 'XX')
				WHERE
					psi2.ps_issue_id in (SELECT ps_issue_id from #item_calculations);
				

		INSERT INTO #error_info (ps_issue_id, obligor_id, industry_name, facility_id)
			SELECT
				psi.ps_issue_id,
				psi.obligor_id,
				CASE @rating_agency
					WHEN 'DBRS' THEN psi.dbrs_obligor_industry
					WHEN 'KBRA' THEN psi.kbra_obligor_industry
					WHEN 'FR' THEN  psi.fitch_obligor_industry
					WHEN 'MR' THEN  psi.moody_obligor_industry
					WHEN 'SPR' THEN  psi.sp_obligor_industry
					ELSE  psi.moody_obligor_industry
				END,
				psi.facility_id
			FROM
				#item_calculations tp 
				INNER JOIN dbo.PS_issue psi ON tp.ps_issue_id = psi.ps_issue_id
				LEFT OUTER JOIN #error_info mi ON psi.ps_issue_id = mi.ps_issue_id
			WHERE
				mi.ps_issue_id IS NULL
			AND (
				(@rating_agency = 'DBRS' AND (psi.dbrs_obligor_industry IS NULL OR psi.obligor_id IS NULL))
			 OR (@rating_agency = 'KBRA' AND (psi.kbra_obligor_industry IS NULL OR psi.obligor_id IS NULL))
			 OR (@rating_agency = 'FR' AND (psi.fitch_obligor_industry IS NULL OR psi.obligor_id IS NULL))
			 OR	(@rating_agency = 'MR' AND (psi.moody_obligor_industry IS NULL OR psi.obligor_id IS NULL))
			 OR (@rating_agency = 'SPR' AND (psi.sp_obligor_industry IS NULL OR psi.obligor_id IS NULL))
			);
			
			
				

		UPDATE #error_info SET error_details = ISNULL(error_details, '') + '/Obligor Missing' WHERE obligor_id IS NULL;
		UPDATE #error_info SET error_details = ISNULL(error_details, '') + '/Industry Missing' WHERE industry_name IS NULL;
		UPDATE #error_info SET error_details = dbo.RemoveStarting(error_details, '/');

		DELETE mi
		FROM
			#error_info mi
		WHERE
			facility_id IS NOT NULL
		AND ps_issue_id <> (SELECT MIN(ps_issue_id) FROM #error_info mi2 WHERE mi2.facility_id = mi.facility_id);

	
		IF @issue_count = 0
			SELECT @message_code = 'ISSUES_MISSING';
		ELSE IF (SELECT COUNT(*) FROM #obligor_summary WHERE obligor_id IS NULL) > 0
			SELECT @message_code = 'OBLIGOR_MISSING';
		ELSE IF (SELECT COUNT(*) FROM #obligor_summary WHERE industry IS NULL) > 0
			SELECT @message_code = 'INDUSTRY_MISSING';
		ELSE IF @include_regions = 0 AND EXISTS(SELECT COUNT(*) FROM #obligor_summary GROUP BY obligor_id HAVING COUNT(*)>1)
			SELECT @message_code = 'MULT_INDUSTRY';

		IF @message_code IS NOT NULL
			SET @asset_count = 0;
		ELSE
			EXEC dbo.PS_CB_Asset_count @asset_count = @asset_count OUTPUT;

		IF @result_variable2 IS NOT NULL
		BEGIN
			IF (@run_mode <> 'DISP')
				EXEC dbo.PS_Field_update
					@psv_id = @psv_id,
					@field_name = @result_variable2,
					@field_value = @asset_count,
					@applicability_expression = NULL,
					@override_existing_value = 1;
		END		

	
		 IF @message_code IS NOT NULL
		AND @run_mode <> 'SAVE'
		BEGIN

			IF @recordset_code IN ('ALL', 'ERROR_INFO')
			BEGIN
				SET @fields = '[Obligor]=obligor_name_id,[Issuer]=issuer_name_id,[Industry]=tt.industry_name,[Security/Facility Name]=issue_facility_name,[Message] = error_details';
				EXEC dbo.PS_CT_Details_Display 
					@recordset_header = 'Error Details',
					@recordset_code = 'INDUSTRY',
					@table_name = '#error_info',
					@fields = @fields,
					@required_fields = NULL,
					@order_by = 'obligor_name',
					@join_mode = 'JOIN_PS_ISSUE',
					@layout_code = NULL,
					@psv_id = @psv_id,
					@use_display_name = @use_display_name;
			END

		END
		ELSE 
		BEGIN

			IF (@run_mode <> 'DISP')
			BEGIN
		  		
				IF @message_code IS NOT NULL
					SET @industry_diversity_score_char = NULL;

				EXEC dbo.PS_Field_update
					@psv_id = @psv_id,
					@field_name = @result_variable,
					@field_value = @industry_diversity_score_char,
					@override_existing_value = 1,
					@rounding_method = 'NO', --rounding method was already applied--
					@rounding_precision = @rounding_precision,
					@applicability_expression = NULL; --already applied in PS_CB_Balance_Load--
			END		

			IF	@run_mode <> 'SAVE'
			AND @recordset_code IN ('ALL', 'SUMMARY', 'DETAILS', 'UNITSCORE', 'INDUSTRY', 'VARIABLES') 
			BEGIN


				--Variables--
				IF @recordset_code IN ('ALL', 'VARIABLES')
					EXEC dbo.PS_CB_Variables_Display
						@psv_id = @psv_id,
						@run_mode = @run_mode,
						@recordset_code = 'VARIABLES',
						@result_variable = @result_variable,
						@result_variable2 = @result_variable2,
						@formula = NULL,
						@formula2 = NULL,
						@user_id = @user_id,
						@operation_confirmed = @operation_confirmed,
						@silent_mode = @silent_mode;
									
				IF @recordset_code IN ('ALL', 'SUMMARY') 
					SELECT
						'Summary' AS [recordset_header],
						'SUMMARY' AS [recordset_code],
						@numerator AS [Aggregate Balance],
						@asset_count AS [Number of Collateral Debt Securities],
						@obligor_count AS [Total Number of Obligors],
						@average_obligor_balance AS	[Average Balance per Obligor]
						
		
				--Summary details display--
				SET @region_details = CASE WHEN @include_regions = 1 THEN ' "Region" = CASE WHEN em_region_code = ''ALL'' THEN ''All'' ELSE dbo.CodeDesc(''REGION_CODE'', em_region_code) END,' ELSE '' END;
				
				IF @recordset_code IN ('ALL', 'INDUSTRY') 
				BEGIN
					SET @fields = '"Industry" = industry,' + @region_details + '"Aggregate Industry Equivalent Unit Score" = aggr_industry_EUS, "Industry Diversity Score" = industry_diversity_score';
					EXEC dbo.PS_CT_Details_Display 
						@recordset_header = 'Diversity Score by Industry', 
						@recordset_code = 'INDUSTRY',
						@table_name = '#industry_summary',
						@fields = @fields,
						@required_fields = NULL,
						@order_by = 'industry',
						@join_mode = 'STANDALONE',
						@layout_code = NULL,
						@psv_id = @psv_id,
						@use_display_name = @use_display_name;
				END
				
				IF @recordset_code IN ('ALL', 'UNITSCORE') 
				BEGIN
					SET @fields = 'obligor_id, "Obligor"= obligor_name, "Industry " = industry,' + @region_details + '"Balance" = balance, "Average Balance " = average_balance, "Equivalent Unit Score" = equivalent_unit_score';
					EXEC dbo.PS_CT_Details_Display 
						@recordset_header = 'Equivalent Unit Score by Industry, Obligor', 
						@recordset_code = 'UNITSCORE',
						@table_name = '#obligor_summary',
						@fields = @fields,
						@required_fields = NULL,
						@order_by = 'industry, obligor_name',
						@join_mode = 'STANDALONE',
						@layout_code = NULL,
						@psv_id = @psv_id,
						@use_display_name = @use_display_name;
				END
				
			END --@run_mode <> 'SAVE'--
		
		END --@message_code IS NULL--

		--Portfolio details display--
		 IF @recordset_code IN ('ALL', 'DETAILS')
		AND @run_mode <> 'SAVE'
		BEGIN
			SET @extra_fields = ',obligor_id, obligor_name, ' + 
				CASE @rating_agency
					WHEN 'DBRS' THEN 'dbrs_obligor_industry'
					WHEN 'KBRA' THEN 'kbra_obligor_industry'
					WHEN 'FR' THEN  'fitch_obligor_industry'
					WHEN 'MR' THEN  'moody_obligor_industry'
					WHEN 'SPR' THEN  'sp_obligor_industry'
					ELSE  'moody_obligor_industry'
				END;


			IF @include_regions = 1
				SET @extra_fields = @extra_fields + ', Region = dbo.CodeDesc(''REGION_CODE'', ' + 
					CASE @rating_agency
						WHEN 'DBRS' THEN 'dbrs_em_region_code'
						WHEN 'KBRA' THEN 'kbra_em_region_code'
						WHEN 'FR' THEN 'fitch_em_region_code'
						WHEN 'MR' THEN 'moody_em_region_code'
						WHEN 'SPR' THEN 'sp_em_region_code'
						ELSE 'moody_em_region_code'
					END				
				+ ')';
					
			--variables/details--
			EXEC dbo.PS_CB_Balance_Display
				@psv_id = @psv_id,
				@run_mode = @run_mode,
				@recordset_code = 'DETAILS',
				@currency_option = @currency_option,
				@result_variable = @result_variable,
				@result_variable2 = NULL,
				@formula = NULL,
				@formula2 = NULL,
				@aggr_level = @aggr_level,
				@aggregate_attributable_amount = @aggregate_attributable_amount,
				@layout_code = @layout_code,
				@applicability_expression = @applicability_expression,
				@extra_fields = @extra_fields,
				@user_id = @user_id,
				@operation_confirmed = @operation_confirmed,
				@silent_mode = @silent_mode;
							

		END	

		--Success--
		EXEC dbo.cdosys_End_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,
			@starting_tran_count = @tran_count,		
			@pk_id = @pk_id, 
			@operation_confirmed = @operation_confirmed,
			@operation_details = @operation_details,
			@operation_primary_key = @operation_primary_key,
			@message_code = @message_code;		

		IF @@trancount > @tran_count
			COMMIT TRANSACTION @proc_name;
		
	END TRY
	BEGIN CATCH 
		
		IF @@trancount > 0
		BEGIN
		
			DECLARE @stack TABLE (stack_type varchar(25) NOT NULL, proc_id int NOT NULL, nest_level int NOT NULL, stack_message nvarchar(4000) NULL);

			INSERT INTO @stack (stack_type, proc_id, nest_level, stack_message)
				SELECT stack_type, proc_id, nest_level, stack_message FROM #cdosys_Stack WHERE XACT_STATE() = -1 OR nest_level >= @@nestlevel;			
			
			IF XACT_STATE() = -1
				ROLLBACK TRANSACTION;
			ELSE IF @@trancount > @tran_count OR @save_tran = 1
				ROLLBACK TRANSACTION @proc_name;
		
			INSERT INTO #cdosys_Stack(proc_id, nest_level, stack_type, stack_message)
				SELECT proc_id, nest_level, stack_type, stack_message FROM @stack;
			
		END
		
		EXEC dbo.cdosys_Return_UI @proc_id = @@procid, @pk_id = @pk_id, @operation_primary_key = @operation_primary_key, @starting_tran_count = @tran_count;
				
	END CATCH
END;
GO

