﻿-- <% MACRO\HEADER %>
CREATE PROCEDURE [dbo].[PS_CB_Run]
/*******************************************************************
* PURPOSE: Executes a portfolio calculation
* NOTES: 
* AUTHOR: Charles Chen
* CREATED: 12/18/2008  
* MODIFIED 
* DATE		AUTHOR	DESCRIPTION
*-------------------------------------------------------------------
* 05/02/2009	SR	Updated procedure
* 08/04/2009	SC	Added new error handling
* 01/25/2010	SC  Added @raw_value to call for PS_CB_ParameterValue
* 05/29/2013	SC	#3767 Added dynamic parameters (@parameters)
* 10/02/2016	SC	#26073 Codes/fields to varchar(100)
* 04/27/2017	SC	#33578 Added check for waterfall recursion
* 11/29/2018	SC	#53405 Added logic for models
* 06/25/2020	SC	#77348 Added snapshot isolation
* 06/25/2020	SC	#145840 Fix for @pp_id
* 01/13/2021	SC	#156159 Updating logic for Snapshot Isolation Level
* 10/04/2024	SC	#293897 Codes cleanup and unique by model
* 10/07/2025	NA	Added use_display_name for PS_CT_Details_Display
*******************************************************************/
(	
	@psv_id int,	
	@dcb_id int, --Calculation Block id--
	@run_mode lookup_code = 'FULL',	
					/*	SAVE - run and save results, do not display
						DISP - display calculation details, do not save
						FULL - run, save, and display results
					*/
	@recordset_code varchar(50) = 'ALL', --recordset code, if ALL, return all--
	@parameters varchar(MAX) = NULL,
	@layout_code varchar(100) = NULL,
	@nest_level_display tinyint = 1, --calculation blocks use 1, PS_PP_Payment_Step_run uses 2--
	@user_id [user_id] = NULL,
	@operation_confirmed tinyint = 1,
	@silent_mode tinyint = 1,
	@use_display_name bit = 1	
)
AS
BEGIN

	SET NOCOUNT ON;
	SET ARITHABORT ON;

	IF @run_mode = 'DISP'
		SET TRANSACTION ISOLATION LEVEL SNAPSHOT;

	DECLARE
		@stack_message NVARCHAR(4000);


	IF @@NESTLEVEL = 1
	OR OBJECT_ID('tempdb..#cdosys_stack') IS NULL
	BEGIN
		DROP TABLE IF EXISTS #cdosys_stack;
		CREATE TABLE #cdosys_Stack(proc_id INT, nest_level INT, stack_type VARCHAR(25), preserve TINYINT DEFAULT(0), stack_message NVARCHAR(4000));
	END;

	/* don't run waterfall recursively */
	SELECT @stack_message = NULL;
	SELECT @stack_message = stack_message FROM #cdosys_stack WHERE stack_type = 'WATERFALL';
	
	IF ISNULL(@stack_message, 'N/A') = 'Running'
	AND EXISTS (
		SELECT * 
		FROM 
			dbo.DC_Calculation_block b
			INNER JOIN dbo.CCT t ON b.calc_id = t.test_id
		WHERE 
			b.dcb_id = @dcb_id 
		AND t.template_code = 'WATERFALL')
		RETURN;

	BEGIN TRY;

		DECLARE
			@proc_name sysname,
			@tran_count int,
			@save_tran bit = 0,
			@message_code varchar(50),
			@operation_details varchar(1000),
			@operation_primary_key varchar(1000),
			@pk_id int;

		SELECT 
			@proc_name = object_name(@@procid),
			@tran_count = @@trancount,
			@pk_id = @psv_id,
			@operation_primary_key = 'psv_id;' + CAST(@psv_id AS varchar);
			
		EXEC dbo.PS_Generate_debug @proc_id = @@procid,@psv_id = @psv_id, @operation = 'ON';
		
		 IF ISNULL(dbo.ConfigValue('PS_GEN_TRAN', NULL),0) = 1 
		AND dbo.cdosys_ContextInfo_True('NOTRAN') = 0
		BEGIN
			IF @@trancount = 0
				BEGIN TRAN @proc_name;
			ELSE
			BEGIN
				SAVE TRAN @proc_name;
				SET @save_tran = 1;
			END
		END



		--Start--
		EXEC dbo.cdosys_Start_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,			
			@starting_tran_count = @tran_count,
			@pk_id = @pk_id, 
			@row_version = NULL, 
			@operation_confirmed = @operation_confirmed;
			
		DECLARE 
			@ps_id int,
			@ts_id int,
			@sql_command nvarchar(MAX),
			@template_type lookup_code,
			@dynamic_proc_name varchar(255),
			@calc_id int,
			@as_of_date datetime,
			@entity_id int,
			@var_name varchar(255),
			@param_value varchar(MAX),
			@value_type lookup_code,
			@param_value_type lookup_code,
			@data_type lookup_code,
			@dcb_param_id int,
			@param_order int,
			@dcg_id int,
			@dcb_description varchar(255),
			@dcg_description varchar(255),
			@portfolio_name varchar(100),
			@field_name varchar(100),
			@format_details varchar(1000),
			@m_id int,
			@pps_id int,
			@pss_id int,
			@pos int,
			@l1 int,
			@len int,
			@opos int,
			@cpos int,
			@ct int,
			@begin int;

		
		DECLARE @params_table TABLE (variable_name varchar(255), variable_value varchar(255));
		
		IF @parameters IS NOT NULL
			INSERT INTO @params_table(variable_name, variable_value)
				SELECT 
					LTRIM(RTRIM(dbo.StringToken(record_string, '=', 1))),
					LTRIM(RTRIM(dbo.StringToken(record_string, '=', 2))) 
				FROM 
					dbo.tf_split2(@parameters, ',');
				
		SELECT
			@ps_id = psv.ps_id,
			@ts_id = psv.ts_id,
			@as_of_date = ps.as_of_date,
			@entity_id = ps.entity_id,
			@m_id = ps.m_id
		FROM 
			dbo.PS_Version psv
			INNER JOIN dbo.PS_Portfolio_Snapshot ps ON ps.ps_id = psv.ps_id
		WHERE 
			psv.psv_id = @psv_id;
		

		--we have to regen the output to get all the good debug info--
		 IF ISNULL(dbo.ConfigValue('PS_GEN_DEBUG', @entity_id),0) = 1 
		AND	@run_mode = 'DISP'
			SET @run_mode = 'FULL';
			
		SELECT 
			@dynamic_proc_name = CASE c.template_type WHEN 'CUST' THEN '#custom_proc' + LTRIM(STR(@dcb_id)) ELSE c.sp_name END,
			@template_type 	= c.template_type,
			@calc_id = c.test_id
		FROM 
			dbo.DC_Calculation_Block t
			INNER JOIN dbo.CCT c ON t.calc_id = c.test_id
		WHERE 
			t.dcb_id = @dcb_id;


		SELECT
			@portfolio_name = deal_name,
			@entity_id = entity_id,
			@dcg_id = dcg_id, 
			@dcb_description = dcb_description,
			@dcg_description = dcg_description
		FROM 
			dbo.DC_Calculation_Block_view
		WHERE
			dcb_id = @dcb_id
		AND entity_id = @entity_id
		AND m_id = @m_id;

		EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'STACK', @stack_message = @dcb_description;

		SELECT @pps_id = pps_id FROM dbo.PP_Payment_Step WHERE dcb_id = @dcb_id AND m_id = @m_id;
		IF @pps_id IS NOT NULL
			SELECT @pss_id = pss_id FROM dbo.PS_PP_Payment_Step WHERE psv_id = @psv_id AND pps_id = @pps_id;
							
		--if we are saving, don't display any results--
		IF @run_mode = 'SAVE'
			SET @recordset_code = 'NONE';
			
		BEGIN TRY
			IF  @template_type = 'CUST' 
			AND @calc_id IS NOT NULL
				EXEC dbo.PS_CB_Custom_SP_create @dcb_id = @dcb_id, @custom_proc_name = @dynamic_proc_name, @recordset_code = @recordset_code;
					

  			SET @sql_command = 'EXEC ' + @dynamic_proc_name +
				+ '  @psv_id = ' + RTRIM(LTRIM(STR(@psv_id)))
				+ ', @dcb_id = ' + RTRIM(LTRIM(STR(@dcb_id)));

			IF @run_mode IS NOT NULL
				SET @sql_command = @sql_command + ',@run_mode=''' + @run_mode + '''';

			IF @recordset_code IS NOT NULL
				SET @sql_command = @sql_command + ',@recordset_code='''+ @recordset_code + '''';

			IF @layout_code IS NOT NULL
				SET @sql_command = @sql_command + ',@layout_code='''+ @layout_code + '''';

			-- To check if the dynamic_proc_name has use_display_name as input parameter or not --
			IF @use_display_name IS NOT NULL AND EXISTS (
			SELECT name,parameter_names  
			FROM (
				SELECT o.[name],  STRING_AGG(p.name, ', ') AS parameter_names
				FROM sys.parameters p
				JOIN sys.objects o ON p.object_id = o.object_id
				WHERE o.type = 'P'
				GROUP BY o.[name]
			) sprocs 
			WHERE COALESCE(LEFT(@dynamic_proc_name, NULLIF(CHARINDEX('@', @dynamic_proc_name), 0) - 1), @dynamic_proc_name)  LIKE '%' + name +'%' 
				AND '@use_display_name' IN(SELECT TRIM(value) FROM STRING_SPLIT(sprocs.parameter_names, ','))
			)
			BEGIN
				SET @sql_command = @sql_command + ',@use_display_name='''+ CAST(@use_display_name AS varchar) + '''';
			END

			--Stored procedure parameters--
			DECLARE param_cursor CURSOR LOCAL READ_ONLY FORWARD_ONLY
			FOR 
				SELECT distinct
					p.param_order,
					p.dcb_param_id,
					p.SQL_variable_name,
					p.value_type,
					p.data_type,
					p.param_value_type
				FROM dbo.DC_CB_Parameter_view p --this view can produce duplicate rows so leave distinct for select--
				WHERE p.dcb_id = @dcb_id
				  AND p.m_id = @m_id
				ORDER BY p.param_order;

			OPEN param_cursor;
			FETCH NEXT FROM param_cursor INTO @param_order, @dcb_param_id, @var_name, @value_type, @data_type, @param_value_type;
			WHILE @@fetch_status = 0
			BEGIN
				SET @param_value = dbo.PS_CB_ParameterValue(@psv_id, @dcb_id, @var_name, NULL,0);
				SET @len = 0;
				SET @ct = 1;
				SET @pos = 0;
				SET @l1= 0;
				SET @begin= 0;
				SET @opos = 0;
				SET @cpos = 0;

				IF @var_name = '@formula'  
					AND (CHARINDEX('CONVERT(float, DATEDIFF (', @param_value) = 0 
					AND CHARINDEX('CONVERT(float, DATEDIFF(', @param_value) = 0)
					AND CHARINDEX('CAST(DATEDIFF', @param_value) = 0
				BEGIN 
					SELECT @pos =  CHARINDEX('DATEDIFF (', @param_value);
					SET @l1 = len('DATEDIFF (');

					IF @pos = 0 
					BEGIN
						SELECT @pos =  CHARINDEX('DATEDIFF(', @param_value);
						SET @l1 = len('DATEDIFF(');
					END
					
					IF @pos > 0
					BEGIN
						SET @begin = @pos;

						SELECT @opos = CHARINDEX('(', @param_value, @begin + @l1); 
						SELECT @cpos = CHARINDEX(')', @param_value, @begin);

						IF (@opos < @cpos AND @opos > 0) 
							SET @ct = @ct + 1; 
						ELSE 
							SET @ct = @ct - 1;

						IF @ct = 0	
							SET @len = @cpos - @pos + 1; 
						ELSE 
							SET @begin = CASE WHEN (@opos < @cpos AND @opos > 0) THEN @opos + 1 ELSE @cpos + 1 END;

						WHILE (@ct <> 0 AND (@opos <> 0 OR @cpos <> 0))
						BEGIN
							SET @opos = NULL;
							SET @cpos = NULL;

							SELECT @opos = CHARINDEX('(', @param_value, @begin); 
							SELECT @cpos = CHARINDEX(')', @param_value, @begin); 

							IF (@opos < @cpos AND @opos > 0) 
								SET @ct = @ct + 1; 
							ELSE 
								SET @ct = @ct - 1;
							
							IF @ct = 0	
								SET @len = @cpos - @pos + 1; 
							ELSE 
								SET @begin = CASE WHEN (@opos < @cpos AND @opos > 0) THEN @opos + 1 ELSE @cpos + 1 END;
						END

						IF @len > 0
						SELECT @param_value = REPLACE(@param_value, substring(@param_value, @pos, @len), 'CAST(' + substring(@param_value, @pos, @len) + ' AS DECIMAL(16,10))');							
					END
				END
				IF NOT EXISTS (SELECT * FROM @params_table WHERE variable_name = LTRIM(RTRIM(@var_name)))
				BEGIN
					SET @sql_command 
						= @sql_command + ', ' 
						+ @var_name + ' = ' 
						+	CASE 
								WHEN ISNULL(@param_value, '') = '' THEN 'DEFAULT'
								WHEN @data_type IN ('N', 'M') AND @value_type NOT IN ('E', 'M') AND @param_value_type <> 'REF' THEN @param_value
								ELSE dbo.QuoteString(@param_value) 
							END;
				END	
				FETCH NEXT FROM param_cursor INTO @param_order, @dcb_param_id, @var_name, @value_type, @data_type, @param_value_type;
			END
			CLOSE param_cursor;
			DEALLOCATE param_cursor;

			IF @parameters IS NOT NULL
				SET @sql_command = @sql_command + ',' + @parameters;
				
			EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'DYNAMICSQL', @stack_message = @sql_command;
			
			 IF @pss_id IS NOT NULL
			AND @sql_command NOT LIKE '%@pp_id%'
				SET @sql_command = 'EXEC dbo.PS_PP_Payment_Step_run @pss_id =' + STR(@pss_id);
			ELSE
			BEGIN
				--Display Test Parameter--
				IF  @run_mode IN ('FULL', 'DISP') 
				AND @recordset_code IN('ALL', 'PARAMS')
				AND dbo.PS_CB_IsFormula(@dcb_id) = 0 --formulas display limited/special details in PS_CB_Formula--
					EXEC dbo.PS_CB_Parameter_list @dcb_id = @dcb_id, @psv_id = @psv_id, @parameters = @parameters;
			END

      --PRINT @sql_command;  

			EXEC (@sql_command);
		END TRY
		BEGIN CATCH
		
			SELECT @format_details = '';
			--this will allow calculation web pages to display the error results in a table--
			IF @@nestlevel = @nest_level_display
				SELECT * FROM dbo.tf_Message_Code(ERROR_MESSAGE());
			ELSE
			BEGIN
				SET @operation_details = char(10) + char(10) + ERROR_MESSAGE();
				
				SELECT @stack_message = NULL;
				SELECT @stack_message = stack_message FROM #cdosys_stack WHERE proc_id = OBJECT_ID('PS_Field_update') AND stack_type = 'FIELDNAME';
				SET @field_name = ISNULL(@stack_message, 'N/A');
				
				EXEC dbo.cdosys_Format_Operation_Details
					@message_code = 'CB_RUN_FAILED',
					@s1 = @portfolio_name, 
					@i2 = @entity_id,
					@s3 = @dcg_description,
					@i4 = @dcg_id,
					@s5 = @dcb_description,
					@i6 = @dcb_id,
					@s7 = @field_name,
					@result = @format_details OUTPUT;
				
				SELECT @stack_message = NULL;
				SELECT @stack_message = stack_message FROM #cdosys_stack WHERE stack_type = 'CB_RUN_FAILED';

				IF @stack_message IS NOT NULL AND @@nestlevel = 4 --calling from Calculations page
					SELECT @format_details = '<br/><br/>' + @format_details;
				ELSE IF @@nestlevel = 5 --calling from ps_generate
				BEGIN
					SELECT @format_details = '

' + @format_details;
				END
				SELECT @format_details = @format_details + ' -> ' + @operation_details;
				EXEC dbo.cdosys_Stack_Put @proc_id = @@procid, @nest_level = @@nestlevel, @stack_type = 'CB_RUN_FAILED', @stack_message = @format_details, @preserve=1;
			END
		END CATCH

		-- Cleanup - delete temp procedure--
		IF (@template_type = 'CUST')
			EXEC ('DROP PROCEDURE ' + @dynamic_proc_name)

		
		
		--Success--
		EXEC dbo.cdosys_End_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,
			@starting_tran_count = @tran_count,		
			@pk_id = @pk_id, 
			@operation_confirmed = @operation_confirmed,
			@operation_details = @operation_details,
			@operation_primary_key = @operation_primary_key,
			@message_code = @message_code;		

		IF @@trancount > @tran_count
			COMMIT TRANSACTION @proc_name;

	
	END TRY
	BEGIN CATCH 
		
		IF @@trancount > 0
		BEGIN
		
			DECLARE @stack TABLE (stack_type varchar(25) NOT NULL, proc_id int NOT NULL, nest_level int NOT NULL, stack_message nvarchar(4000) NULL);

			INSERT INTO @stack (stack_type, proc_id, nest_level, stack_message)
				SELECT stack_type, proc_id, nest_level, stack_message FROM #cdosys_Stack WHERE XACT_STATE() = -1 OR nest_level >= @@nestlevel;			
			
			IF XACT_STATE() = -1
				ROLLBACK TRANSACTION;
			ELSE IF @@trancount > @tran_count OR @save_tran = 1
				ROLLBACK TRANSACTION @proc_name;
		
			INSERT INTO #cdosys_Stack(proc_id, nest_level, stack_type, stack_message)
				SELECT proc_id, nest_level, stack_type, stack_message FROM @stack;

		END
		
		EXEC dbo.cdosys_Return_UI @proc_id = @@procid, @pk_id = @pk_id, @operation_primary_key = @operation_primary_key, @starting_tran_count = @tran_count;
				
	END CATCH
	
	EXEC dbo.PS_Generate_debug @proc_id = @@procid, @psv_id = @psv_id, @operation = 'OFFD';	
END;
GO

-- <% MACRO\HEADER %>
CREATE PROCEDURE [dbo].[PS_CB_Balance_Display]
/*******************************************************************
* PURPOSE:  Displays the results for portfolio balance calculators
* NOTES: 
* DATE CREATED: 1/27/2010 scaffo
* MODIFIED 
* DATE		AUTHOR		DESCRIPTION
*-------------------------------------------------------------------
*03/12/2014	SC	#4512 Added @result_variable3
*11/19/2014	SC	#5905 Handle null @balance_currency
*12/17/2014	SC	#4941 Removed cusip
*02/11/2016	SC	#14773 Added error details results
*10/02/2016	SC	#26073 Codes/fields to varchar(100)
*09/28/2021	TK	#195832. #208615. Added @filter parameter
*******************************************************************/
(
	@psv_id int,
	@run_mode lookup_code,	
		/*	SAVE - run and save results, do not display
			DISP - display calculation details, do not save
			FULL - run, save, and display results
		*/
	@recordset_code varchar(50) = 'ALL', --ALL, DETAILS, VARIABLES, ERROR_INFO--
	@result_variable varchar(50) = NULL,	
	@result_variable2 varchar(50) = NULL,
	@result_variable3 varchar(50) = NULL,
	@formula varchar(max),	
	@formula2 varchar(max) = NULL,	
	@currency_option lookup_code,
		/* 
			To aggregate, amounts must be in the same currency. So Either 
			   a)only look up issues with a specified currency or 
			   b)convert to a single currency
			'DEAL' - convert all balances to one functional currency
			'USD' - restrict issue or account to a single currency 
		*/	
	@aggr_level lookup_code,
	@aggregate_attributable_amount lookup_code, 
		/*  
			value to use aggregate attributable amount		
			'AA' - use where available
			'IC' - use issuer country only
		*/	
	@layout_code varchar(100) = NULL,
	@applicability_expression varchar(MAX) = NULL,
	@extra_fields varchar(MAX) = NULL,
	@no_variable_currency tinyint = 0,
	@exclude_pbal tinyint = 0,
	@table_name varchar(255) = '#item_calculations',
	@filter varchar(max) = NULL,
	@user_id [user_id] = NULL,
	@operation_confirmed tinyint = 1,
	@silent_mode tinyint = 1			
	
)
AS
BEGIN

	SET NOCOUNT ON;
	BEGIN TRY;

		DECLARE
			@proc_name sysname,
			@tran_count int,
			@save_tran bit = 0,
			@message_code varchar(50),
			@operation_details varchar(1000),
			@operation_primary_key varchar(1000),
			@pk_id int;

		SELECT 
			@proc_name = object_name(@@procid),
			@tran_count = @@trancount,
			@pk_id = @psv_id,
			@operation_primary_key = 'psv_id;' + CAST(@psv_id AS varchar);
			
		
		IF @@NESTLEVEL = 1
		OR OBJECT_ID('tempdb..#cdosys_stack') IS NULL
		BEGIN
			DROP TABLE IF EXISTS #cdosys_stack;
			CREATE TABLE #cdosys_Stack(proc_id INT, nest_level INT, stack_type VARCHAR(25), preserve TINYINT DEFAULT(0), stack_message NVARCHAR(4000));
		END;

		 IF ISNULL(dbo.ConfigValue('PS_GEN_TRAN', NULL),0) = 1 
		AND dbo.cdosys_ContextInfo_True('NOTRAN') = 0
		BEGIN
			IF @@trancount = 0
				BEGIN TRAN @proc_name;
			ELSE
			BEGIN
				SAVE TRAN @proc_name;
				SET @save_tran = 1;
			END
		END



		--Start--
		EXEC dbo.cdosys_Start_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,			
			@starting_tran_count = @tran_count,
			@pk_id = @pk_id, 
			@row_version = NULL, 
			@operation_confirmed = @operation_confirmed;

		 IF @layout_code IS NOT NULL
		AND ISNULL(dbo.LayoutAggrLevel(dbo.LayoutID(@layout_code)),  'ISSU') = 'ITEM'
			SELECT @aggr_level = 'ITEM';

		CREATE TABLE #country_codes ( field_code varchar(25) NOT NULL, field_code_desc varchar(255) NOT NULL);
		
		DECLARE
			@ps_id int,
			@ts_id int,
			@field_id int,
			@join_mode varchar(50),
			@balance_currency lookup_code,
			@variable_currency lookup_code,
			@fields varchar(MAX),
			@required_fields varchar(MAX);
			
							
		--Details--
		IF @run_mode <> 'SAVE'
		AND @recordset_code IN ('ALL', 'DETAILS', 'VARIABLES', 'ERROR_INFO')
		BEGIN 
			SELECT @ps_id = ps_id, @ts_id = ts_id FROM dbo.PS_Version WHERE psv_id = @psv_id;
			SELECT @balance_currency = CASE WHEN @currency_option = 'DEAL' THEN dbo.DealCurrency(dbo.PS_EntityId(@ps_id)) ELSE @currency_option END;
			
			SET @variable_currency = @balance_currency;
			IF @no_variable_currency = 1
				SET @variable_currency = NULL;
				
			--Variables--
			IF @recordset_code IN ('ALL', 'VARIABLES')
				EXEC dbo.PS_CB_Variables_Display
					@psv_id = @psv_id,
					@run_mode = @run_mode,
					@recordset_code = 'VARIABLES',
					@result_variable = @result_variable,
					@result_variable2 = @result_variable2,
					@result_variable3 = @result_variable3,
					@formula = @formula,
					@formula2 = @formula2,
					@currency_option = @variable_currency,
					@user_id = @user_id,
					@operation_confirmed = @operation_confirmed,
					@silent_mode = @silent_mode;

			--update country descriptions--
			SET @field_id = dbo.ExpFieldID('country_code');

			INSERT INTO #country_codes(field_code, field_code_desc)
				SELECT field_code, field_code_desc FROM dbo.tf_FieldCode(@field_id);

			EXEC ('
			UPDATE ' + @table_name + '
			SET 
				country_name = field_code_desc
			FROM 
				' + @table_name + '
				INNER JOIN #country_codes cc ON ' + @table_name + '.country_code = cc.field_code;');

			EXEC ('
			UPDATE ' + @table_name + '
			SET 
				obligor_country_name = field_code_desc
			FROM 
				' + @table_name + ' 
				INNER JOIN #country_codes cc ON ' + @table_name + '.obligor_country_code = cc.field_code;');

			IF @aggregate_attributable_amount = 'AA'
				SET @applicability_expression = REPLACE(REPLACE(@applicability_expression, 'tn.[country_code]', '[tt.country_name]'), 'tn.[obligor_country_code]', '[tt.obligor_country_name]');
			ELSE 
				SET @applicability_expression = REPLACE(REPLACE(@applicability_expression, 'PS_Issue.[country_code]', '[PS_Issue.country_name]'), 'PS_Issue.[obligor_country_code]', '[PS_Issue.obligor_country_name]');

			SET @join_mode = CASE @aggr_level WHEN 'ISSU' THEN 'JOIN_PS_ISSUE' WHEN 'ITEM' THEN 'JOIN_PS_ITEM' END;
			
			IF @exclude_pbal = 0
				SET @required_fields = '[Principal Balance]=balance,'
			ELSE
				SET @required_fields = ''
			
			SET @required_fields = @required_fields + ISNULL('table_$$$ = ' + dbo.QuoteString(@balance_currency), '') + ISNULL(@extra_fields, '');
			SET @fields = 'PS_Issue.issue_id, issuer_name, facility_name, CASE tt.ps_issue_id WHEN  -1 THEN ''Cash'' WHEN -2 THEN ''Eligible Investments'' ELSE issue_name END as ''Issue Name'', ' + @required_fields;
			

			IF @recordset_code IN ('ALL', 'DETAILS')
				EXEC dbo.PS_CT_Details_Display 
					@recordset_header = 'Portfolio Details', 
					@recordset_code = 'DETAILS',
					@table_name = @table_name,
					@fields = @fields,
					@required_fields = @required_fields,
					@order_by = 'issuer_name, issue_name',
					@filter = @filter,
					@expression = @applicability_expression, --display @applicability_expression fields--
					@join_mode = @join_mode,
					@layout_code = @layout_code,
					@psv_id = @psv_id;
		
			 IF @recordset_code IN ('ERROR_INFO') /* don't check 'ALL' here, ERROR_INFO should be explicit */
				EXEC dbo.PS_CT_Details_Display 
					@recordset_header = 'Error Details', 
					@recordset_code = 'ERROR_INFO',
					@table_name = @table_name,
					@fields = @fields,
					@required_fields = @required_fields,
					@order_by = 'issuer_name, issue_name',
					@filter = @filter,
					@expression = @applicability_expression, --display @applicability_expression fields--
					@join_mode = @join_mode,
					@layout_code = @layout_code,
					@psv_id = @psv_id;
		END
		
		--Success--
		EXEC dbo.cdosys_End_Procedure 
			@proc_id = @@procid,
			@user_id = @user_id,
			@silent_mode = @silent_mode,
			@starting_tran_count = @tran_count,		
			@pk_id = @pk_id, 
			@operation_confirmed = @operation_confirmed,
			@operation_details = @operation_details,
			@operation_primary_key = @operation_primary_key,
			@message_code = @message_code;		

		IF @@trancount > @tran_count
			COMMIT TRANSACTION @proc_name;
		
	END TRY
	BEGIN CATCH 
		
		IF @@trancount > 0
		BEGIN
		
			DECLARE @stack TABLE (stack_type varchar(25) NOT NULL, proc_id int NOT NULL, nest_level int NOT NULL, stack_message nvarchar(4000) NULL);

			INSERT INTO @stack (stack_type, proc_id, nest_level, stack_message)
				SELECT stack_type, proc_id, nest_level, stack_message FROM #cdosys_Stack WHERE XACT_STATE() = -1 OR nest_level >= @@nestlevel;			
			
			IF XACT_STATE() = -1
				ROLLBACK TRANSACTION;
			ELSE IF @@trancount > @tran_count OR @save_tran = 1
				ROLLBACK TRANSACTION @proc_name;
		
			INSERT INTO #cdosys_Stack(proc_id, nest_level, stack_type, stack_message)
				SELECT proc_id, nest_level, stack_type, stack_message FROM @stack;
			
		END
		
		EXEC dbo.cdosys_Return_UI @proc_id = @@procid, @pk_id = @pk_id, @operation_primary_key = @operation_primary_key, @starting_tran_count = @tran_count;
				
	END CATCH
END;
